import React from "react";

const Review = () => {
  return (
    <>
      <div className="container">
        <div className="header-container">
          <h1 className="heading">Powered by Leading Cloud-Native Companies</h1>
          <p className="heading1">Backed by Top Cloud-Native Enterprises</p>
        </div>
      </div>
    </>
  );
};

export default Review;
